css:
.loader {
  position: relative;
  width: 0;
  height: 0;
  border: 24px solid;
  border-color: #ff3b3b transparent #ff3b3b transparent;
  animation: rubyPinwheelSpin 2s linear infinite;
}
.loader::before,
.loader::after {
  content: "";
  display: block;
  border: 24px solid transparent;
  border-left-color: #ff3b3b;
  position: absolute;
  left: -24px;
  top: -24px;
  animation: rubyPinwheelFold 1s infinite ease-in;
  transform-origin: 0% 100%;
}
.loader::before {
  border-color: transparent #ff3b3b transparent transparent;
  transform-origin: 100% 0%;
  animation-delay: 0.5s;
}
@keyframes rubyPinwheelSpin { to { transform: rotate(360deg); } }
@keyframes rubyPinwheelFold { 20%, 80% { transform: rotate(0); } 50% { transform: rotate(-90deg); } }
